module.exports = {
  // Version and protocol
  MCPS_VERSION,
  SUPPORTED_VERSIONS,
  TRUST_LEVELS,
  ERROR_CODES,

  // Limits
  MAX_ISSUER_CHAIN_DEPTH,
  MAX_PASSPORT_BYTES,
  MAX_CAPABILITIES,

  // RFC 8785 Canonicalization
  canonicalJSON,

  // Key management
  generateKeyPair,
  publicKeyToJWK,

  // Passports
  createPassport,
  signPassport,
  verifyPassportSignature,
  isPassportExpired,
  validatePassportFormat,
  validateOrigin,
  getEffectiveTrustLevel,
  verifyIssuerChain,

  // Message signing
  signMessage,
  verifyMessage,

  // Tool integrity
  signTool,
  verifyTool,

  // Transcript binding (anti-downgrade) -- uses ECDSA signatures, not MAC
  createTranscriptBinding,
  verifyTranscriptBinding,
  createTranscriptMAC,       // backwards-compatible alias
  verifyTranscriptMAC,       // backwards-compatible alias

  // Version negotiation
  negotiateVersion,

  // Revocation
  checkRevocation,

  // Middleware
  secureMCP,
  secureMCPClient,

  // HSM/KMS support
  createExternalSigner,
  derToP1363,

  // Internals
  NonceStore,
};
